import{_ as a,c as s,o,ah as t}from"./chunks/framework.C-x9UAyH.js";const r="/efs/efs_1.png",n="/efs/efs_2.png",i="/efs/efs_3.png",l="/efs/efs_4.png",c="/efs/efs_5.png",d="/efs/efs_6.png",p="/efs/efs_7.png",m="/efs/efs_8.png",g="/efs/efs_9.png",u="/efs/efs_10.png",f="/efs/efs_11.png",_="/efs/efs_12.png",h="/efs/efs_13.png",b="/efs/efs_14.png",E="/efs/efs_15.png",S="/efs/efs_16.png",q="/efs/efs_17.png",v="/efs/efs_18.png",C="/efs/efs_19.png",y="/efs/efs_20.png",w="/efs/efs_21.png",F="/efs/efs_22.png",P="/efs/efs_23.png",A="/efs/efs_24.png",j="/efs/efs_25.png",k="/efs/efs_26.png",x="/efs/efs_27.png",z="/efs/efs_28.png",N="/efs/efs_29.png",T="/efs/efs_30.png",B="/efs/efs_31.png",L="/efs/efs_32.png",D="/efs/efs_33.png",M="/efs/efs_34.png",V="/efs/efs_35.png",G="/efs/efs_36.png",I="/efs/efs_37.png",W=JSON.parse('{"title":"Amazon Elastic File System (EFS)","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"aws/elastic_file_system.md","filePath":"aws/elastic_file_system.md","lastUpdated":1760459112000}'),$={name:"aws/elastic_file_system.md"};function R(U,e,J,O,H,K){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="amazon-elastic-file-system-efs" tabindex="-1">Amazon Elastic File System (EFS) <a class="header-anchor" href="#amazon-elastic-file-system-efs" aria-label="Permalink to &quot;Amazon Elastic File System (EFS)&quot;">​</a></h1><p>Amazon EFS proporciona <strong>almacenamiento de archivos escalable</strong> para su uso con Amazon EC2. Puede crear un sistema de archivos de EFS y configurar las instancias para montar el sistema de archivos. Puede usar un sistema de archivos de EFS como un origen de datos común para aplicaciones y cargas de trabajo que se ejecutan en varias instancias.</p><h2 id="instancias-ec2" tabindex="-1">Instancias EC2 <a class="header-anchor" href="#instancias-ec2" aria-label="Permalink to &quot;Instancias EC2&quot;">​</a></h2><p align="center"><img src="'+r+'" width="800" alt="efs 1"></p><ol><li>Lanzamiento de instancia EC2-A. Sección &quot;Detalle&quot;.</li></ol><br><p align="center"><img src="'+n+'" width="800" alt="efs 2"></p><ol start="2"><li>Lanzamiento de instancia EC2-B. Sección &quot;Detalle&quot;.</li></ol><br><p align="center"><img src="'+i+'" width="800" alt="efs 3"></p><ol start="3"><li>Conexión a máquina EC2-A.</li></ol><br><p align="center"><img src="'+l+'" width="800" alt="efs 4"></p><ol start="4"><li>Conexión a máquina EC2-B.</li></ol><h2 id="crear-un-grupo-de-seguridad" tabindex="-1">Crear un grupo de seguridad <a class="header-anchor" href="#crear-un-grupo-de-seguridad" aria-label="Permalink to &quot;Crear un grupo de seguridad&quot;">​</a></h2><br><p align="center"><img src="'+c+'" width="800" alt="efs 5"></p><ol start="5"><li>Crear grupo de seguridad. En el ítem “Red y seguridad”, se selecciona el botón “Crear grupo de seguridad”. Se le asigna un nombre, en este caso My-SG-EFS y la VPC por defecto.</li></ol><br><p align="center"><img src="'+d+'" width="800" alt="efs 6"></p><ol start="6"><li>Se le asigna “Reglas de entrada” donde el tipo es NFS, el origen “Personalizado” el cual va a ser el grupo de seguridad creado anteriormente.</li></ol><h2 id="creacion-de-sistema-de-archivos-efs" tabindex="-1">Creación de Sistema de archivos EFS <a class="header-anchor" href="#creacion-de-sistema-de-archivos-efs" aria-label="Permalink to &quot;Creación de Sistema de archivos EFS&quot;">​</a></h2><br><p align="center"><img src="'+p+'" width="800" alt="efs 7"></p><ol start="7"><li>En la página principal buscar “Elastic File System” y hacer click en el botón “Crear un sistema de archivos”.</li></ol><br><p align="center"><img src="'+m+'" width="800" alt="efs 8"></p><ol start="8"><li>Agregar un nombre. Se debe seleccionar la VPC predeterminada y hacer click en el botón “Personalizar”.</li></ol><br><p align="center"><img src="'+g+'" width="800" alt="efs 9"></p><ol start="9"><li>Se debe quitar el check a “Permitir copias de seguridad automáticas”. En la sección “Administración del ciclo de vida” se debe seleccionar la opción “Ninguno” en “Transición a infrequent Access” y “Transición a archivo”.</li></ol><br><p align="center"><img src="'+u+'" width="800" alt="efs 10"></p><ol start="10"><li>Se puede crear una etiqueta indicando en el campo “Clave de la etiqueta” un nombre y en el campo “Valor de la etiqueta” el valor, en este caso “efsprueba”. Luego seleccionar “Siguiente”.</li></ol><br><p align="center"><img src="'+f+'" width="800" alt="efs 11"></p><ol start="11"><li>Entrar al ítem “Grupos de seguridad”. Seleccionar el grupo de seguridad y se puede ver el detalle. Si se hace click en el botón “Editar reglas de seguridad” se puede crear un grupo de seguridad sólo para el EFS que permita la entrada de las EC2.</li></ol><br><p align="center"><img src="'+_+'" width="800" alt="efs 12"></p><ol start="12"><li>Creación del grupo de seguridad. Se le asigna el nombre “My-SG-EFS”. La VPC seleccionada es predeterminada y las reglas de entrada se escoge el tipo “NFS”, su origen “Personalizada” y se selecciona el default. Luego se hace click al botón “Crear grupo de seguridad”.</li></ol><br><p align="center"><img src="'+h+'" width="800" alt="efs 13"></p><ol start="13"><li>Si se regresa a la lista de grupo de seguridad, se muestra el grupo. Entonces si se regresa a la pestaña EFS, se puede seleccionar el grupo de seguridad que se creó (My-SG-EFS) a ambas zonas de disponibilidad (us-east-1a y us-east-1b). Por último seleccionar el botón siguiente.</li></ol><br><p align="center"><img src="'+b+'" width="800" alt="efs 14"></p><ol start="14"><li>El paso “Política de sistema de archivo” no se debe editar, sólo seleccionar “siguiente”. Luego se mostrará un resumen de lo realizado y se hace click al botón “Crear”.</li></ol><h2 id="montar-el-efs-en-instancias-ec2" tabindex="-1">Montar el EFS en instancias EC2 <a class="header-anchor" href="#montar-el-efs-en-instancias-ec2" aria-label="Permalink to &quot;Montar el EFS en instancias EC2&quot;">​</a></h2><p align="center"><img src="'+E+'" width="800" alt="efs 15"></p><ol start="15"><li>Si se selecciona el nombre del EFS muestra el detalle del EFS creado. El punto de acceso es el que se llama “Nombre de DNS” que está disponible para copiar. Luego se selecciona el botón “Asociar”.</li></ol><br><p align="center"><img src="'+S+'" width="800" alt="efs 16"></p><ol start="16"><li>Se abre una ventana donde aparece el comando que se debe ejecutar dentro de la máquina EC2 para que monte el directorio, mediante el cliente de NFS.</li></ol><br><p align="center"><img src="'+q+'" width="800" alt="efs 17"></p><ol start="17"><li>Entonces al regresar a las instancias EC2 y seleccionar una, se debe dar click a “Conectar”. De este modo, se abrirá la consola.</li></ol><br><p align="center"><img src="'+v+'" width="800" alt="efs 18"></p><ol start="18"><li>En la consola del EC2-A, se debe crear el directorio <strong>efs</strong> mediante el comando <strong>mkdir efs</strong>, se puede chequear que está instalado el efs-utils mediante el comando <strong>sudo yum list nfs-utils</strong>.</li></ol><br><p align="center"><img src="'+C+'" width="800" alt="efs 19"></p><ol start="19"><li>En la consola del EC2-B, también se debe crear el directorio <strong>efs</strong> mediante el comando <strong>mkdir efs</strong></li></ol><br><p align="center"><img src="'+y+'" width="800" alt="efs 20"></p><ol start="20"><li>Al regresar a la pantalla de EFS, se copia el comando para montar el sistema de archivo EFS mediante el cliente de NFS.</li></ol><br><p align="center"><img src="'+w+'" width="800" alt="efs 21"></p><ol start="21"><li>En la instancia EC2-A, una vez montado el EFS instalamos los nfs-utils mediante el comando <strong>sudo yum list nfs-utils</strong></li></ol><br><p align="center"><img src="'+F+'" width="800" alt="efs 22"></p><ol start="22"><li>Se monta el EFS mediante el comando <strong>sudo mount -t …. / efs</strong> que se copió anteriormente.</li></ol><ul><li>Se ejecuta el comando <strong>cd efs/</strong> para ingresar a la carpeta efs.</li><li>Se ejecuta el comando <strong>pwd</strong> para saber en qué directorio se encuentra posicionado.</li><li>Se ejecuta el comando <strong>df -hT .</strong> para ver la información del sistema de archivo donde se está ubicado, y se puede ver que está el punto de montaje.</li></ul><h2 id="pruebas-de-acceso-compartido" tabindex="-1">Pruebas de acceso compartido <a class="header-anchor" href="#pruebas-de-acceso-compartido" aria-label="Permalink to &quot;Pruebas de acceso compartido&quot;">​</a></h2><p align="center"><img src="'+P+'" width="800" alt="efs 23"></p><ol start="23"><li>En máquina EC2-A, dentro del directorio efs, se crean los archivos archivo1.txt y archivo2.txt mediante el comando <strong>sudo touch archivo1.txt</strong> y <strong>sudo touch archivo2.txt</strong>. Se muestran que ya están creados mediante el comando <strong>ls -ltr</strong></li></ol><br><p align="center"><img src="'+A+'" width="800" alt="efs 24"></p><ol start="24"><li>Luego, en la máquina EC2-B, se crea el directorio efs mediante el comando mkdir efs y con el comando ls -ltr se verifica que ya está creado el efs. Entonces se ejecuta el comando sudo mount… efs</li></ol><br><p align="center"><img src="'+j+'" width="800" alt="efs 25"></p><ol start="25"><li>Una vez ejecutado el comando sudo mount en la máquina EC2-B, se procede a listar los archivos con el comando ls -ltr donde se puede ver el directorio efs creado. Luego se ingresa a esta carpeta usando el comando cd efs/ y estando dentro de efs se ejecuta el comando ls -ltr donde se puede ver los archivos compartidos que fueron creados en la instancia EC2-A.</li></ol><h2 id="persistencia" tabindex="-1">Persistencia <a class="header-anchor" href="#persistencia" aria-label="Permalink to &quot;Persistencia&quot;">​</a></h2><p>Para prevenir y que la máquina, en caso de un reinicio o apagado, siempre levante un punto de montaje, lo ideal es que la máquina vuelva a estar disponible con la misma data persistente y se pueda ver los mismos archivos que contenga para leerlos o editarlos. Para eso, se debe dejar fijo en un archivo de configuración que se llama <strong>fstab</strong> donde se encuentran todos los puntos de montaje de la máquina linux.</p><p align="center"><img src="'+k+'" width="800" alt="efs 26"></p><ol start="26"><li>Mediante el comando <strong>sudo vim /etc/fstab</strong> se ingresa al archivo de configuración.</li></ol><br><p align="center"><img src="'+x+'" width="800" alt="efs 27"></p><ol start="27"><li>Copiar el Nombre de DNS del EFS.</li></ol><br><p align="center"><img src="'+z+'" width="800" alt="efs 28"></p><ol start="28"><li>Dentro de la consola de la EC2-B se agrega esta línea (con la letra <strong>a</strong> se ingresa a modo de edición). Se debe tener en cuenta que la primera línea de color celeste corresponde al nombre de DNS del EFS. Luego se digita <strong>Esc</strong> + <strong>:wq!</strong> para salir del modo edición.</li></ol><br><p align="center"><img src="'+N+'" width="800" alt="efs 29"></p><ol start="29"><li>Se verifica que el archivo está editado con el comando df -hT . , luego se regresa un directorio con el comando cd .. para salir de la carpeta efs, por último, se ejecuta el comando sudo umount /home/ec2-user/efs para desmontar el efs.</li></ol><br><p align="center"><img src="'+T+'" width="800" alt="efs 30"></p><ol start="30"><li>Si se vuelve a ingresar al directorio efs (<strong>cd efs/</strong>) y se ejecuta nuevamente el comando <strong>df -hT .</strong> , se puede ver que ya no está montado.</li></ol><br><p align="center"><img src="'+B+'" width="800" alt="efs 31"></p><ol start="31"><li>En la máquina EC2-B, se regresa un directorio (cd ..) y se ejecuta el comando sudo reboot con el fin de no ejecutar el comando mount nuevamente, ya que solo por defecto, al editar el archivo fstab queda por defecto dentro de los sistemas de arranque.</li></ol><br><p align="center"><img src="'+L+'" width="800" alt="efs 32"></p><ol start="32"><li>Mientras tanto, en la máquina EC2-A se comprueba que está montado con el comando <strong>df -hT .</strong> y se pueden ver los archivos con el comando <strong>ls -ltr</strong></li></ol><br><p align="center"><img src="'+D+'" width="800" alt="efs 33"></p><ol start="33"><li>Se regresa un directorio con el comando <strong>cd ..</strong> y se ejecuta el comando <strong>sudo umount /home/ec2-user/efs</strong> para desmontar el efs.</li></ol><br><p align="center"><img src="'+M+'" width="800" alt="efs 34"></p><ol start="34"><li>Se monta el EFS en la EC2-A</li></ol><br><p align="center"><img src="'+V+'" width="800" alt="efs 35"></p><ol start="35"><li>Se monta el EFS en la EC2-B</li></ol><br><p align="center"><img src="'+G+'" width="800" alt="efs 36"></p><ol start="36"><li>En el EC2-A, dentro de la carpeta efs/ con el comando <strong>ls -ltrh</strong> se muestran los archivos creados</li></ol><br><p align="center"><img src="'+I+'" width="800" alt="efs 37"></p><ol start="36"><li>En el EC2-B, dentro de la carpeta efs/ con el comando <strong>ls -ltrh</strong> se muestran los archivos creados</li></ol>',117)])])}const X=a($,[["render",R]]);export{W as __pageData,X as default};
